export const rawHtml = "{% extends \"base.html\" %}\r\n\r\n{% block title %}Analizlerim - Arsa Analiz Platformu{% endblock %}\r\n\r\n{% block meta_description %}Arsa analizlerinizi görüntüleyin, filtreleyin ve yönetin. Detaylı analiz raporlarına erişin.{% endblock %}\r\n\r\n{% block extra_css %}\r\n<!-- Bootstrap Icons -->\r\n<link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.7.2/font/bootstrap-icons.css\">\r\n{% endblock %}\r\n\r\n{% block content %}\r\n<!-- Page Header -->\r\n<div class=\"mb-6\">\r\n  <div class=\"flex flex-col sm:flex-row sm:items-center sm:justify-between\">\r\n    <div>\r\n      <h1 class=\"text-2xl font-bold text-gray-900 mb-2\">Analizlerim</h1>\r\n      <p class=\"text-gray-600\">Arsa analizlerinizi görüntüleyin ve yönetin</p>\r\n    </div>\r\n    <div class=\"mt-4 sm:mt-0\">\r\n      <a href=\"{{ url_for('main.analysis_form') }}\" class=\"btn btn-primary\">\r\n        <i class=\"fas fa-plus mr-2\"></i>Yeni Analiz\r\n      </a>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<!-- Arama ve Filtreleme Bölümü -->\r\n<div class=\"bg-white rounded-lg shadow-sm border border-gray-200 mb-6\">\r\n  <div class=\"p-6\">\r\n    <form id=\"filterForm\" class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4\">\r\n      <div>\r\n        <label for=\"searchText\" class=\"block text-sm font-medium text-gray-700 mb-2\">Arama</label>\r\n        <input\r\n          type=\"text\"\r\n          class=\"form-control\"\r\n          id=\"searchText\"\r\n          placeholder=\"Konum, mahalle ara...\"\r\n        />\r\n      </div>\r\n      <div>\r\n        <label for=\"filterIl\" class=\"block text-sm font-medium text-gray-700 mb-2\">İl</label>\r\n        <select class=\"form-select\" id=\"filterIl\">\r\n          <option value=\"\">Tüm İller</option>\r\n          {% for il_item in iller %}\r\n          <option value=\"{{ il_item }}\">{{ il_item }}</option>\r\n          {% endfor %}\r\n        </select>\r\n      </div>\r\n      <div>\r\n        <label for=\"filterImarDurumu\" class=\"block text-sm font-medium text-gray-700 mb-2\">İmar Durumu</label>\r\n        <select class=\"form-select\" id=\"filterImarDurumu\">\r\n          <option value=\"\">Tüm İmar Durumları</option>\r\n          <option value=\"konut\">Konut</option>\r\n          <option value=\"ticari\">Ticari</option>\r\n          <option value=\"karma\">Karma</option>\r\n          <option value=\"sanayi\">Sanayi</option>\r\n          <option value=\"diger\">Diğer</option>\r\n        </select>\r\n      </div>\r\n      <div>\r\n        <label for=\"sortBy\" class=\"block text-sm font-medium text-gray-700 mb-2\">Sıralama</label>\r\n        <select class=\"form-select\" id=\"sortBy\">\r\n          <option value=\"date_desc\">Tarihe Göre (Yeni-Eski)</option>\r\n          <option value=\"date_asc\">Tarihe Göre (Eski-Yeni)</option>\r\n          <option value=\"price_desc\">Fiyata Göre (Yüksek-Düşük)</option>\r\n          <option value=\"price_asc\">Fiyata Göre (Düşük-Yüksek)</option>\r\n        </select>\r\n      </div>\r\n    </form>\r\n  </div>\r\n</div>\r\n\r\n<!-- Analiz Listesi -->\r\n{% for month, month_analizler in grouped_analizler.items() %}\r\n<div class=\"mb-8\">\r\n  <h3 class=\"text-lg font-semibold text-gray-900 mb-4 border-b border-gray-200 pb-2\">{{ month }}</h3>\r\n  <div class=\"grid grid-cols-1 lg:grid-cols-2 gap-6\">\r\n    {% for analiz_item_loop in month_analizler %}\r\n    <div class=\"analysis-card bg-white rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow duration-200\">\r\n      <div class=\"p-6\">\r\n        <div class=\"flex items-start justify-between mb-4\">\r\n          <div>\r\n            <h5 class=\"text-lg font-semibold text-gray-900 mb-1\">\r\n              {{ analiz_item_loop.il }}, {{ analiz_item_loop.ilce }}\r\n            </h5>\r\n            <p class=\"text-sm text-gray-600\">{{ analiz_item_loop.mahalle }}</p>\r\n          </div>\r\n          <div class=\"flex space-x-2\">\r\n            <a\r\n              href=\"{{ url_for('analysis.analiz_detay', analiz_id=analiz_item_loop.id) }}\"\r\n              class=\"btn btn-sm btn-outline-primary\"\r\n              title=\"Analizi Görüntüle\"\r\n            >\r\n              <i class=\"fas fa-eye\"></i>\r\n            </a>\r\n            <button\r\n              onclick=\"confirmDelete('{{ analiz_item_loop.id }}')\"\r\n              class=\"btn btn-sm btn-outline-danger\"\r\n              title=\"Analizi Sil\"\r\n            >\r\n              <i class=\"fas fa-trash\"></i>\r\n            </button>\r\n          </div>\r\n        </div>\r\n\r\n        <div class=\"grid grid-cols-2 gap-4 mb-4\">\r\n          <div class=\"flex items-center space-x-3\">\r\n            <div class=\"flex-shrink-0\">\r\n              <div class=\"w-8 h-8 bg-blue-100 rounded-lg flex items-center justify-center\">\r\n                <i class=\"fas fa-ruler-combined text-blue-600 text-sm\"></i>\r\n              </div>\r\n            </div>\r\n            <div>\r\n              <p class=\"text-xs text-gray-500 uppercase tracking-wide\">Alan</p>\r\n              <p class=\"text-sm font-semibold text-gray-900\">\r\n                {{ \"{:,.0f}\".format(analiz_item_loop.metrekare) }} m²\r\n              </p>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"flex items-center space-x-3\">\r\n            <div class=\"flex-shrink-0\">\r\n              <div class=\"w-8 h-8 bg-green-100 rounded-lg flex items-center justify-center\">\r\n                <i class=\"fas fa-lira-sign text-green-600 text-sm\"></i>\r\n              </div>\r\n            </div>\r\n            <div>\r\n              <p class=\"text-xs text-gray-500 uppercase tracking-wide\">m² Fiyatı</p>\r\n              <p class=\"text-sm font-semibold text-gray-900\">\r\n                {{ \"{:,.0f}\".format(analiz_item_loop.fiyat / analiz_item_loop.metrekare if analiz_item_loop.metrekare else 0) }} ₺\r\n              </p>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"flex items-center space-x-3\">\r\n            <div class=\"flex-shrink-0\">\r\n              <div class=\"w-8 h-8 bg-yellow-100 rounded-lg flex items-center justify-center\">\r\n                <i class=\"fas fa-building text-yellow-600 text-sm\"></i>\r\n              </div>\r\n            </div>\r\n            <div>\r\n              <p class=\"text-xs text-gray-500 uppercase tracking-wide\">İmar</p>\r\n              <p class=\"text-sm font-semibold text-gray-900\" data-imar=\"{{ analiz_item_loop.imar_durumu|title }}\">\r\n                {{ analiz_item_loop.imar_durumu|title }}\r\n              </p>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"flex items-center space-x-3\">\r\n            <div class=\"flex-shrink-0\">\r\n              <div class=\"w-8 h-8 bg-purple-100 rounded-lg flex items-center justify-center\">\r\n                <i class=\"fas fa-tag text-purple-600 text-sm\"></i>\r\n              </div>\r\n            </div>\r\n            <div>\r\n              <p class=\"text-xs text-gray-500 uppercase tracking-wide\">Toplam Fiyat</p>\r\n              <p class=\"text-sm font-semibold text-gray-900\" data-price=\"{{ analiz_item_loop.fiyat }}\">\r\n                {{ \"{:,.0f}\".format(analiz_item_loop.fiyat) }} ₺\r\n              </p>\r\n            </div>\r\n          </div>\r\n        </div>\r\n\r\n        <div class=\"flex items-center justify-between pt-4 border-t border-gray-100\">\r\n          <div class=\"flex items-center text-sm text-gray-500\">\r\n            <i class=\"fas fa-calendar-alt mr-2\"></i>\r\n            <span data-date=\"{{ analiz_item_loop.created_at }}\">\r\n              {{ analiz_item_loop.created_at.strftime('%d.%m.%Y') }}\r\n            </span>\r\n          </div>\r\n          <div class=\"flex items-center space-x-2\">\r\n            <a\r\n              href=\"{{ url_for('analysis.analiz_detay', analiz_id=analiz_item_loop.id) }}\"\r\n              class=\"text-sm text-blue-600 hover:text-blue-800 font-medium\"\r\n            >\r\n              Detayları Gör\r\n            </a>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    {% endfor %}\r\n  </div>\r\n</div>\r\n{% endfor %}\r\n\r\n{% if not grouped_analizler %}\r\n<div class=\"text-center py-12\">\r\n  <div class=\"max-w-md mx-auto\">\r\n    <div class=\"w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4\">\r\n      <i class=\"fas fa-chart-line text-gray-400 text-2xl\"></i>\r\n    </div>\r\n    <h3 class=\"text-lg font-medium text-gray-900 mb-2\">Henüz analiz yok</h3>\r\n    <p class=\"text-gray-600 mb-6\">İlk arsa analizinizi oluşturarak başlayın.</p>\r\n    <a href=\"{{ url_for('main.analysis_form') }}\" class=\"btn btn-primary\">\r\n      <i class=\"fas fa-plus mr-2\"></i>Yeni Analiz Oluştur\r\n    </a>\r\n  </div>\r\n</div>\r\n{% endif %}\r\n\r\n<!-- Silme Onay Modalı -->\r\n<div class=\"modal fade\" id=\"deleteModal\" tabindex=\"-1\" aria-labelledby=\"deleteModalLabel\" aria-hidden=\"true\">\r\n  <div class=\"modal-dialog\">\r\n    <div class=\"modal-content\">\r\n      <div class=\"modal-header border-b border-gray-200\">\r\n        <h5 class=\"modal-title font-semibold text-gray-900\" id=\"deleteModalLabel\">\r\n          <i class=\"fas fa-exclamation-triangle text-red-500 mr-2\"></i>Analizi Sil\r\n        </h5>\r\n        <button type=\"button\" class=\"btn-close\" data-bs-dismiss=\"modal\" aria-label=\"Close\"></button>\r\n      </div>\r\n      <div class=\"modal-body py-6\">\r\n        <div class=\"flex items-center space-x-3\">\r\n          <div class=\"flex-shrink-0\">\r\n            <div class=\"w-10 h-10 bg-red-100 rounded-full flex items-center justify-center\">\r\n              <i class=\"fas fa-trash text-red-600\"></i>\r\n            </div>\r\n          </div>\r\n          <div>\r\n            <p class=\"text-gray-900 font-medium\">Bu analizi silmek istediğinizden emin misiniz?</p>\r\n            <p class=\"text-gray-600 text-sm mt-1\">Bu işlem geri alınamaz.</p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n      <div class=\"modal-footer border-t border-gray-200 flex justify-end space-x-3\">\r\n        <button type=\"button\" class=\"btn btn-secondary\" data-bs-dismiss=\"modal\">\r\n          İptal\r\n        </button>\r\n        <form id=\"deleteForm\" method=\"POST\" class=\"inline\">\r\n          <button type=\"submit\" class=\"btn btn-danger\">\r\n            <i class=\"fas fa-trash mr-2\"></i>Sil\r\n          </button>\r\n        </form>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>\r\n{% endblock %}\r\n\r\n{% block extra_js %}\r\n<script>\r\n  function confirmDelete(analizId) {\r\n    const deleteForm = document.getElementById(\"deleteForm\");\r\n    // URL'i doğru Blueprint ve rota adı ile oluşturun\r\n    deleteForm.action = `{{ url_for('analysis.analiz_sil', analiz_id=0) }}`.replace(\"/0\", `/${analizId}`);\r\n    const deleteModal = new bootstrap.Modal(document.getElementById(\"deleteModal\"));\r\n    deleteModal.show();\r\n  }\r\n\r\n  document.addEventListener(\"DOMContentLoaded\", function () {\r\n    const searchText = document.getElementById(\"searchText\");\r\n    const filterIl = document.getElementById(\"filterIl\");\r\n    const filterImarDurumu = document.getElementById(\"filterImarDurumu\");\r\n    const sortBy = document.getElementById(\"sortBy\");\r\n\r\n    function filterCards() {\r\n      const cards = document.querySelectorAll(\".analysis-card\");\r\n      const search = searchText.value.toLowerCase().trim();\r\n      const selectedIl = filterIl.value.toLowerCase().trim();\r\n      const selectedImar = filterImarDurumu.value.toLowerCase().trim();\r\n\r\n      cards.forEach((card) => {\r\n        const titleElement = card.querySelector(\"h5\");\r\n        const imarElement = card.querySelector(\"[data-imar]\");\r\n\r\n        if (!titleElement || !imarElement) return;\r\n\r\n        const fullText = titleElement.textContent.toLowerCase();\r\n        const imar = imarElement.getAttribute(\"data-imar\").toLowerCase();\r\n\r\n        const matchesSearch = !search || fullText.includes(search);\r\n        const matchesIl = !selectedIl || fullText.includes(selectedIl);\r\n        const matchesImar = !selectedImar || imar === selectedImar;\r\n\r\n        // Kartın parent container'ını gizle/göster\r\n        const parentContainer = card.closest(\".grid > div\");\r\n        if (parentContainer) {\r\n          parentContainer.style.display = matchesSearch && matchesIl && matchesImar ? \"\" : \"none\";\r\n        }\r\n      });\r\n    }\r\n\r\n    function sortCards() {\r\n      const containers = document.querySelectorAll(\".grid.grid-cols-1.lg\\\\:grid-cols-2.gap-6\");\r\n\r\n      containers.forEach((container) => {\r\n        // Sadece görünür kartları al\r\n        const cards = Array.from(container.children).filter((cardDiv) => cardDiv.style.display !== \"none\");\r\n\r\n        cards.sort((a, b) => {\r\n          const cardA = a.querySelector(\".analysis-card\");\r\n          const cardB = b.querySelector(\".analysis-card\");\r\n          if (!cardA || !cardB) return 0;\r\n\r\n          const valueA = getSortValue(cardA);\r\n          const valueB = getSortValue(cardB);\r\n\r\n          switch (sortBy.value) {\r\n            case \"date_asc\":\r\n              return valueA.date - valueB.date;\r\n            case \"date_desc\":\r\n              return valueB.date - valueA.date;\r\n            case \"price_asc\":\r\n              return valueA.price - valueB.price;\r\n            case \"price_desc\":\r\n              return valueB.price - valueA.price;\r\n            default:\r\n              return 0;\r\n          }\r\n        });\r\n\r\n        // Sıralanmış kartları container'a yeniden ekle\r\n        cards.forEach((cardDiv) => container.appendChild(cardDiv));\r\n      });\r\n    }\r\n\r\n    function getSortValue(cardElement) {\r\n      const dateElement = cardElement.querySelector(\"[data-date]\");\r\n      const priceElement = cardElement.querySelector(\"[data-price]\");\r\n\r\n      return {\r\n        date: dateElement ? new Date(dateElement.getAttribute(\"data-date\")) : new Date(0),\r\n        price: priceElement ? parseFloat(priceElement.getAttribute(\"data-price\")) : 0,\r\n      };\r\n    }\r\n\r\n    // Event listeners\r\n    [searchText, filterIl, filterImarDurumu, sortBy].forEach((element) => {\r\n      if (element) {\r\n        element.addEventListener(\"change\", () => {\r\n          filterCards();\r\n          if ([\"date_asc\", \"date_desc\", \"price_asc\", \"price_desc\"].includes(sortBy.value)) {\r\n            sortCards();\r\n          }\r\n        });\r\n\r\n        if (element === searchText) {\r\n          element.addEventListener(\"input\", () => {\r\n            filterCards();\r\n            if ([\"date_asc\", \"date_desc\", \"price_asc\", \"price_desc\"].includes(sortBy.value)) {\r\n              sortCards();\r\n            }\r\n          });\r\n        }\r\n      }\r\n    });\r\n  });\r\n</script>\r\n{% endblock %}\r\n";

export default function AnalysisAnalizler(props: { html?: string; wrapperClassName?: string }) {
  const { html = rawHtml, wrapperClassName } = props;
  return (
    <div className={wrapperClassName} dangerouslySetInnerHTML={{ __html: html }} />
  );
}
